import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProposalsList() {
  const [proposals, setProposals] = useState([]);
  const [userRole, setUserRole] = useState('');
  const [filter, setFilter] = useState('all');
  const navigate = useNavigate();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const token = localStorage.getItem('access');
      const userRes = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUserRole(userRes.data.role);

      const res = await axios.get('http://127.0.0.1:8000/api/proposals/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProposals(res.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleAccept = async (id) => {
    const token = localStorage.getItem('access');
    await axios.patch(`http://127.0.0.1:8000/api/proposals/${id}/`,
      { status: 'accepted' },
      { headers: { Authorization: `Bearer ${token}` } }
    );
    fetchData();
  };

  const handleReject = async (id) => {
    const token = localStorage.getItem('access');
    await axios.patch(`http://127.0.0.1:8000/api/proposals/${id}/`,
      { status: 'rejected' },
      { headers: { Authorization: `Bearer ${token}` } }
    );
    fetchData();
  };

  const filtered = filter === 'all' ? proposals : proposals.filter(p => p.status === filter);

  return (
    <div className="proposals-container">
      <h2>Proposals</h2>
      <select onChange={(e) => setFilter(e.target.value)} value={filter}>
        <option value="all">All</option>
        <option value="pending">Pending</option>
        <option value="accepted">Accepted</option>
        <option value="rejected">Rejected</option>
      </select>
      {filtered.map(p => (
        <div key={p.id} className="proposal-card">
          <h3>{p.project_title}</h3>
          <p>👤 {p.freelancer_name}</p>
          <p>💰 ₹{p.bid_amount} | ⏱️ {p.estimated_days} days</p>
          <p>Status: {p.status}</p>
          {userRole === 'CLIENT' && p.status === 'pending' && (
            <div>
              <button onClick={() => handleAccept(p.id)}>Accept</button>
              <button onClick={() => handleReject(p.id)}>Reject</button>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

export default ProposalsList;
